9. 图片问题
文章中插入图片就两种方式, 利用图床或者插入本地的图片. 我个人对插入图片很有执念, 因为mermaid太难用了.
然而我个人不放心图床的方式, 有跑路的风险(, 决定用本地的图片.
这样有一个问题, 如果图片数量过多, 仓库的体积就会很大, 后面甚至不能push, 所以我决定采用压缩图片的方法. 流程上:
用一个log文件记录图片是否被压缩过了-&gt;没压缩就压缩,压缩过了就不管-&gt;备份文件到GitHub私密仓库-&gt;部署到公开仓库
Pillow 是 Python 最流行的图像处理库，用于压缩图片。
pip install pillow
默认把所有文章的图片放在:
source/images/article_images
我们的文章在:
source/_post
所以图片的相对路径是:
../images/article_images
下面是测试文件, 原大小为653KB:

python处理脚本(博客根目录下的compress_images.py):
import osfrom pathlib import Pathfrom PIL import Image# ==================== 配置区 ====================BLOG_DIR = Path(__file__).parentSOURCE_DIR = BLOG_DIR / &quot;source&quot;LOG_FILE = BLOG_DIR / &quot;.compressed_log&quot;# 压缩参数JPEG_QUALITY = 82          # JPEG 质量 (1-100)PNG_COMPRESS_LEVEL = 8     # PNG 压缩级别 (1-9)SUPPORTED_FORMATS = &#123;&quot;.jpg&quot;, &quot;.jpeg&quot;, &quot;.png&quot;&#125;# ==================== 核心逻辑 ====================def load_log():    if LOG_FILE.exists():        return set(LOG_FILE.read_text(encoding=&quot;utf-8&quot;).splitlines())    return set()def save_log(log_set):    LOG_FILE.write_text(&quot;\n&quot;.join(sorted(log_set)), encoding=&quot;utf-8&quot;)def compress_image(filepath, log_set):    rel_path = str(filepath.relative_to(BLOG_DIR))        # 1. 检查是否已压缩过    if rel_path in log_set:        return &quot;skip&quot;, 0, 0    original_size = filepath.stat().st_size    # 使用临时文件，防止压缩后体积反而变大时破坏原图    temp_path = filepath.with_name(filepath.name + &quot;.tmp&quot;)         try:        with Image.open(filepath) as img:            suffix = filepath.suffix.lower()                        if suffix in &#123;&quot;.jpg&quot;, &quot;.jpeg&quot;&#125;:                if img.mode in (&quot;RGBA&quot;, &quot;P&quot;):                    img = img.convert(&quot;RGB&quot;)                img.save(temp_path, &quot;JPEG&quot;, quality=JPEG_QUALITY, optimize=True)                        elif suffix == &quot;.png&quot;:                if img.mode == &quot;RGBA&quot;:                    img.save(temp_path, &quot;PNG&quot;, optimize=True, compress_level=PNG_COMPRESS_LEVEL)                else:                    img = img.convert(&quot;P&quot;, palette=Image.ADAPTIVE, colors=256)                    img.save(temp_path, &quot;PNG&quot;, optimize=True, compress_level=PNG_COMPRESS_LEVEL)                new_size = temp_path.stat().st_size                # 2. 判断压缩效果        if new_size &lt; original_size:            os.replace(temp_path, filepath)  # 替换原文件            return &quot;success&quot;, original_size, new_size        else:            os.remove(temp_path)  # 删除临时文件，保留原图            return &quot;skip_opt&quot;, original_size, original_size                except Exception as e:        if temp_path.exists():            os.remove(temp_path)        return &quot;error&quot;, original_size, 0def main():    print(&quot;=&quot; * 55)    print(&quot; Hexo Image Compressor&quot;)    print(&quot;=&quot; * 55)        # 扫描图片    images = []    for ext in SUPPORTED_FORMATS:        images.extend(SOURCE_DIR.rglob(f&quot;*&#123;ext&#125;&quot;))            log_set = load_log()    success_count = 0    skip_count = 0        print(f&quot;\nScanning &#123;len(images)&#125; images in &#x27;source/&#x27;...\n&quot;)        # 处理图片    for img_path in images:        rel_path = str(img_path.relative_to(BLOG_DIR))        status, orig, new = compress_image(img_path, log_set)                if status == &quot;success&quot;:            ratio = (1 - new / orig) * 100            print(f&quot;  [OK]   &#123;rel_path&#125; (&#123;orig/1024:.1f&#125;KB -&gt; &#123;new/1024:.1f&#125;KB, -&#123;ratio:.1f&#125;%)&quot;)            log_set.add(rel_path)            success_count += 1        elif status == &quot;skip&quot;:            skip_count += 1        elif status == &quot;skip_opt&quot;:            print(f&quot;  [SKIP] &#123;rel_path&#125; (Already optimized)&quot;)            log_set.add(rel_path)            skip_count += 1        elif status == &quot;error&quot;:            print(f&quot;  [ERR]  &#123;rel_path&#125; (Failed)&quot;)                # 保存日志    if success_count &gt; 0 or skip_count &gt; 0:        save_log(log_set)            print(f&quot;\nSummary: &#123;success_count&#125; compressed, &#123;skip_count&#125; skipped.&quot;)    print(&quot;=&quot; * 55)if __name__ == &quot;__main__&quot;:    main()
